let _currentAnim = _ANIM_DATA[0]?.name || 'idle';
let _currentFrame = 0;
let _frameTimer = 0;
const _frameTextures = {};

function loadSpritesheet(gl, imageSrc) {
  const img = new Image();
  img.src = imageSrc;
  img.onload = () => {
    for (const anim of _ANIM_DATA) {
      for (const frame of anim.frames) {
        const canvas = document.createElement('canvas');
        canvas.width = frame.width || 128;
        canvas.height = frame.height || 128;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, frame.x || 0, frame.y || 0, frame.width || 128, frame.height || 128, 0, 0, canvas.width, canvas.height);
        const tex = gl.createTexture();
        gl.bindTexture(gl.TEXTURE_2D, tex);
        gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, canvas);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.NEAREST);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.NEAREST);
        _frameTextures[frame.name] = tex;
      }
    }
    console.log('✅ Spritesheet carregada');
  };
}

function updateAnimation(dt) {
  const anim = _ANIM_DATA.find(a => a.name === _currentAnim);
  if (!anim) return null;
  _frameTimer += dt * 1000;
  const frame = anim.frames[_currentFrame];
  const frameDuration = frame.duration || anim.frameDuration || 42;
  if (_frameTimer >= frameDuration) {
    _frameTimer = 0;
    _currentFrame++;
    if (_currentFrame >= anim.frames.length) {
      _currentFrame = anim.loop !== false ? 0 : anim.frames.length - 1;
    }
  }
  return _frameTextures[anim.frames[_currentFrame].name] || null;
}

function setAnimation(name) {
  if (_ANIM_DATA.find(a => a.name === name)) {
    _currentAnim = name;
    _currentFrame = 0;
    _frameTimer = 0;
  }
}

window.GameModel2D = (() => {
  function create(gl, sprite2D) {
    const img = new Image();
    img.src = 'data:image/png;base64,';
    const texture = gl.createTexture();
    gl.bindTexture(gl.TEXTURE_2D, texture);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, 1, 1, 0, gl.RGBA, gl.UNSIGNED_BYTE, new Uint8Array([255,255,255,255]));
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
    img.onload = () => {
      gl.bindTexture(gl.TEXTURE_2D, texture);
      gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, img);
      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
      if (typeof loadSpritesheet === 'function') loadSpritesheet(gl, 'data:image/png;base64,');
    };
    const size = 256;
    return {
      render: function(time, canvasWidth, canvasHeight) {
        const x = canvasWidth/2, y = canvasHeight/2;
        gl.enable(gl.BLEND);
        gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
        let tex = texture;
        if (typeof updateAnimation === 'function') {
          const animTex = updateAnimation(0.016);
          if (animTex) tex = animTex;
        }
        sprite2D.drawSprite(tex, x, y, size, size, { alpha: 1, color: [1,1,1,1], time });
        gl.disable(gl.BLEND);
      }
    };
  }
  return { create };
})();